CREATE TABLE if not exists admin_users (
id INT AUTO_INCREMENT PRIMARY KEY,
username VARCHAR(50) UNIQUE,
password VARCHAR(255)
);

CREATE TABLE if not exists pages (
  id INT PRIMARY KEY AUTO_INCREMENT,
  slug VARCHAR(50),
  `schema` JSON,
  updated_at TIMESTAMP
);

CREATE TABLE if not exists page_versions (
  id INT AUTO_INCREMENT PRIMARY KEY,
  page_id INT NOT NULL,
  `schema` LONGTEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  note VARCHAR(255) NULL
);

INSERT INTO `pages` (`id`, `slug`, `schema`, `updated_at`) VALUES
(1, 'home', '{\n    \"page\": \"home\",\n    \"sections\": [\n        {\n            \"type\": \"hero\",\n            \"id\": \"hero\",\n            \"enabled\": true,\n            \"data\": {\n                \"title\": \"Ankit Sharma\",\n                \"tagline\": \"Software Engineer • Researcher • Educator\\r\\nBuilding technology, knowledge systems, and tools that remove superstition and empower minds.\",\n                \"photo\": \"1769965383_hero.jpg\"\n            }\n        },\n        {\n            \"type\": \"navigation\",\n            \"id\": \"main-nav\",\n            \"enabled\": true,\n            \"data\": {\n                \"links\": [\n                    {\n                        \"text\": \"About\",\n                        \"href\": \"#about\"\n                    },\n                    {\n                        \"text\": \"Skills\",\n                        \"href\": \"#skills\"\n                    },\n                    {\n                        \"text\": \"Projects\",\n                        \"href\": \"#projects\"\n                    },\n                    {\n                        \"text\": \"Vision\",\n                        \"href\": \"#vision\"\n                    },\n                    {\n                        \"text\": \"Contact\",\n                        \"href\": \"#contact\"\n                    }\n                ]\n            }\n        },\n        {\n            \"type\": \"content\",\n            \"id\": \"about\",\n            \"enabled\": true,\n            \"data\": {\n                \"title\": \"About Me\",\n                \"text\": \"I am a software engineer from Jabalpur, India, with a background in both diploma and B.Tech engineering. I work across low-level systems, web technologies, simulations, and research-driven projects. Alongside development, I teach, write books, and work toward building open knowledge institutions.\"\n            }\n        },\n        {\n            \"type\": \"skills\",\n            \"id\": \"skills\",\n            \"enabled\": true,\n            \"data\": {\n                \"title\": \"Skills\",\n                \"items\": [\n                    \"C \\/ C++\",\n                    \"Python\",\n                    \"Go\",\n                    \"PHP\",\n                    \"JavaScript\",\n                    \"Linux (Fedora)\",\n                    \"MySQL\",\n                    \"System Design\",\n                    \"Data Structures & Algorithms\",\n                    \"Research & Development\"\n                ]\n            }\n        },\n        {\n            \"type\": \"projects\",\n            \"id\": \"projects\",\n            \"enabled\": true,\n            \"data\": {\n                \"title\": \"Projects\",\n                \"items\": [\n                    {\n                        \"title\": \"Fitness & Health Simulation Platform\",\n                        \"description\": \"Athlete-first training and nutrition system with deep physiological logic, focusing on recovery, amino-acid utilization, and realistic body adaptation models.\",\n                        \"image\": \"1769965383_project_0.Jpg\"\n                    },\n                    {\n                        \"title\": \"Celestial & Atmospheric Illusion Simulations\",\n                        \"description\": \"Python-based visual simulations explaining planetary illusions (Jupiter, night sky, atmosphere) using physics, motion, and perceptual science.\",\n                        \"image\": \"1769965383_project_1.Jpg\"\n                    },\n                    {\n                        \"title\": \"Knowledge & Education Platforms\",\n                        \"description\": \"Web platforms, books, and planned Gurukul-style education systems combining ancient texts with modern science and technology.\",\n                        \"image\": \"1769965383_project_2.Jpg\"\n                    }\n                ]\n            }\n        },\n        {\n            \"type\": \"content\",\n            \"id\": \"vision\",\n            \"enabled\": true,\n            \"data\": {\n                \"title\": \"Vision\",\n                \"text\": \"My long-term vision is to build libraries, research centers, and technologies that make humanity richer in knowledge, logical thinking, and scientific temperament. Technology is my tool — clarity is my goal.\"\n            }\n        },\n        {\n            \"type\": \"contact\",\n            \"id\": \"contact\",\n            \"enabled\": true,\n            \"data\": {\n                \"title\": \"Contact\",\n                \"items\": [\n                    {\n                        \"name\": \"Email\",\n                        \"value\": \"as4808385@gmail.com\"\n                    },\n                    {\n                        \"name\": \"GitHub\",\n                        \"value\": \"https:\\/\\/github.com\\/ankit123618\"\n                    },\n                    {\n                        \"name\": \"YouTube\",\n                        \"value\": \"@ankitbhai123618\"\n                    }\n                ]\n            }\n        },\n        {\n            \"type\": \"footer\",\n            \"id\": \"footer\",\n            \"enabled\": true,\n            \"data\": {\n                \"text\": \"© 2026 Ankit Sharma • Built on Linux with clarity and purpose\"\n            }\n        }\n    ]\n}', '2026-02-01 17:03:03');

